import json
import pandas as pd
from typing import List, Dict, Tuple, Any
from pathlib import Path
from .models import MainRecord, SupplementRecord, ValidationRule, GradingCriteria, GradeLevel


class DataReader:
    @staticmethod
    def _read_file(file_path: str) -> pd.DataFrame:
        path = Path(file_path)
        if not path.exists():
            raise FileNotFoundError(f"文件不存在: {file_path}")

        suffix = path.suffix.lower()
        if suffix == '.csv':
            return pd.read_csv(file_path, dtype=str).fillna('')
        elif suffix in ['.xlsx', '.xls']:
            return pd.read_excel(file_path, dtype=str).fillna('')
        elif suffix == '.json':
            with open(file_path, 'r', encoding='utf-8') as f:
                data = json.load(f)
            return pd.DataFrame(data) if isinstance(data, list) else pd.DataFrame([data])
        else:
            raise ValueError(f"不支持的文件格式: {suffix}")

    @staticmethod
    def read_main_list(file_path: str) -> Tuple[List[MainRecord], List[Dict[str, Any]]]:
        df = DataReader._read_file(file_path)
        records = []
        bad_rows = []

        required_cols = ['id', 'supplier_name', 'tea_variety', 'harvest_date', 
                        'quantity', 'unit_price', 'moisture_content', 
                        'leaf_integrity', 'tenderness', 'color']

        for idx, row in df.iterrows():
            row_num = idx + 2
            raw_data = row.to_dict()

            missing_fields = [col for col in required_cols if not str(row.get(col, '')).strip()]
            if missing_fields:
                bad_rows.append({
                    'row_number': row_num,
                    'raw_data': raw_data,
                    'reason': f"缺少必填字段: {', '.join(missing_fields)}"
                })
                continue

            try:
                record = MainRecord(
                    id=str(row['id']).strip(),
                    supplier_name=str(row['supplier_name']).strip(),
                    tea_variety=str(row['tea_variety']).strip(),
                    harvest_date=str(row['harvest_date']).strip(),
                    quantity=float(row['quantity']),
                    unit_price=float(row['unit_price']),
                    moisture_content=float(row['moisture_content']),
                    leaf_integrity=float(row['leaf_integrity']),
                    tenderness=float(row['tenderness']),
                    color=str(row['color']).strip(),
                    remark=str(row.get('remark', '')).strip(),
                    raw_data=raw_data
                )
                records.append(record)
            except (ValueError, KeyError) as e:
                bad_rows.append({
                    'row_number': row_num,
                    'raw_data': raw_data,
                    'reason': f"数据格式错误: {str(e)}"
                })

        return records, bad_rows

    @staticmethod
    def read_supplement(file_path: str) -> Dict[str, SupplementRecord]:
        df = DataReader._read_file(file_path)
        supplements = {}

        for idx, row in df.iterrows():
            raw_data = row.to_dict()
            try:
                main_id = str(row['main_id']).strip()
                supplement = SupplementRecord(
                    id=str(row.get('id', f"S{idx+1}")).strip(),
                    main_id=main_id,
                    inspector=str(row['inspector']).strip(),
                    inspection_time=str(row['inspection_time']).strip(),
                    actual_moisture=float(row['actual_moisture']),
                    actual_integrity=float(row['actual_integrity']),
                    actual_tenderness=float(row['actual_tenderness']),
                    sampling_photo=str(row.get('sampling_photo', '')).strip(),
                    inspection_remark=str(row.get('inspection_remark', '')).strip(),
                    raw_data=raw_data
                )
                supplements[main_id] = supplement
            except (ValueError, KeyError):
                continue

        return supplements

    @staticmethod
    def read_validation_rules(file_path: str) -> List[ValidationRule]:
        with open(file_path, 'r', encoding='utf-8') as f:
            data = json.load(f)

        rules_data = data.get('validation_rules', []) if isinstance(data, dict) else data
        rules = []

        for rule_data in rules_data:
            rule = ValidationRule(
                field_name=rule_data['field_name'],
                rule_type=rule_data['rule_type'],
                min_value=rule_data.get('min_value'),
                max_value=rule_data.get('max_value'),
                allowed_values=rule_data.get('allowed_values'),
                required=rule_data.get('required', True),
                description=rule_data.get('description', ''),
                severity=rule_data.get('severity', 'error')
            )
            rules.append(rule)

        return rules

    @staticmethod
    def read_grading_criteria(file_path: str) -> List[GradingCriteria]:
        with open(file_path, 'r', encoding='utf-8') as f:
            data = json.load(f)

        criteria_data = data.get('grading_criteria', []) if isinstance(data, dict) else data
        criteria_list = []

        for crit_data in criteria_data:
            criteria = GradingCriteria(
                grade=GradeLevel(crit_data['grade']),
                min_moisture=float(crit_data['min_moisture']),
                max_moisture=float(crit_data['max_moisture']),
                min_integrity=float(crit_data['min_integrity']),
                min_tenderness=float(crit_data['min_tenderness']),
                price_adjustment=float(crit_data.get('price_adjustment', 0))
            )
            criteria_list.append(criteria)

        return criteria_list

    @staticmethod
    def read_history_record(file_path: str) -> Dict[str, Dict[str, Any]]:
        df = DataReader._read_file(file_path)
        history = {}

        for _, row in df.iterrows():
            main_id = str(row.get('main_id', row.get('id', ''))).strip()
            if main_id:
                history[main_id] = row.to_dict()

        return history
