from datetime import datetime
from .models import MainRecord, SupplementRecord, ValidationRule, BadRowReason


class ValidationEngine:
    def __init__(self, rules: List[ValidationRule]):
        self.rules = rules

    def validate_main_record(self, record: MainRecord, 
                           supplements: Dict[str, SupplementRecord],
                           seen_ids: set,
                           history_data: Optional[Dict[str, Dict[str, Any]]] = None
                           ) -> Tuple[bool, Optional[str], Dict[str, Dict[str, Any]]]:
        errors = []
        diff_fields = {}

        if record.id in seen_ids:
            return False, f"{BadRowReason.DUPLICATE_ID.value}: {record.id}", diff_fields

        if record.id not in supplements:
            errors.append(f"{BadRowReason.NO_SUPPLEMENT.value}: 缺少质检补充记录")

        for rule in self.rules:
            field_value = getattr(record, rule.field_name, None)

            if field_value is None or (isinstance(field_value, str) and not field_value.strip()):
                if rule.required:
                    errors.append(f"{BadRowReason.MISSING_FIELD.value}: {rule.field_name}")
                continue

            if rule.rule_type == 'range':
                if not isinstance(field_value, (int, float)):
                    try:
                        field_value = float(field_value)
                    except ValueError:
                        errors.append(f"{BadRowReason.INVALID_FORMAT.value}: {rule.field_name} 应为数字")
                        continue

                if rule.min_value is not None and field_value < rule.min_value:
                    errors.append(f"{BadRowReason.OUT_OF_RANGE.value}: {rule.field_name}={field_value} 低于最小值 {rule.min_value}")
                if rule.max_value is not None and field_value > rule.max_value:
                    errors.append(f"{BadRowReason.OUT_OF_RANGE.value}: {rule.field_name}={field_value} 高于最大值 {rule.max_value}")

            elif rule.rule_type == 'enum':
                if rule.allowed_values and field_value not in rule.allowed_values:
                    errors.append(f"{BadRowReason.RULE_VIOLATION.value}: {rule.field_name}='{field_value}' 不在允许值列表 {rule.allowed_values}")

            elif rule.rule_type == 'date':
                try:
                    datetime.strptime(str(field_value), '%Y-%m-%d')
                except ValueError:
                    try:
                        datetime.strptime(str(field_value), '%Y/%m/%d')
                    except ValueError:
                        errors.append(f"{BadRowReason.INVALID_FORMAT.value}: {rule.field_name} 日期格式错误，应为YYYY-MM-DD")

        if history_data and record.id in history_data:
            hist = history_data[record.id]
            for field in ['moisture_content', 'leaf_integrity', 'tenderness', 'quantity']:
                if field in hist:
                    try:
                        hist_val = float(hist[field])
                        curr_val = float(getattr(record, field))
                        if abs(curr_val - hist_val) > 0.01:
                            diff_fields[field] = {
                                'history': hist_val,
                                'current': curr_val,
                                'diff': round(curr_val - hist_val, 4)
                            }
                    except (ValueError, TypeError):
                        continue

        return len(errors) == 0, "; ".join(errors) if errors else None, diff_fields

    def validate_parameters(self, main_file: str, supplement_file: str, 
                           rules_file: str, output_dir: str) -> List[str]:
        import os
        errors = []

        if not main_file:
            errors.append("主清单文件路径不能为空")
        elif not os.path.exists(main_file):
            errors.append(f"主清单文件不存在: {main_file}")

        if not supplement_file:
            errors.append("补充表文件路径不能为空")
        elif not os.path.exists(supplement_file):
            errors.append(f"补充表文件不存在: {supplement_file}")

        if not rules_file:
            errors.append("校验规则文件路径不能为空")
        elif not os.path.exists(rules_file):
            errors.append(f"校验规则文件不存在: {rules_file}")

        if output_dir:
            os.makedirs(output_dir, exist_ok=True)

        return errors
